EJ_EncounterSectionDB[2010] = { Title = "Stage One: Fists of Flame and Frost", Desc = "", JournalEncounterID = 89, OrderIndex = 1, ParentSectionID = 0, FirstChildSectionID = 2011, NextSiblingSectionID = 2014, Type = 0, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 1, IconFlags = 0, DifficultyMask = -1};
EJ_EncounterSectionDB[2011] = { Title = "Fists of Flame", Desc = "Glubtok shrouds his fists in flame, causing each of his melee attacks that land to deal $87874s1 Fire damage. Additionally, when Glubtok lands a melee attack he will sometimes deal $87896s1 Fire damage and knock up nearby enemies within $87896A1 yards.", JournalEncounterID = 89, OrderIndex = 2, ParentSectionID = 2010, FirstChildSectionID = 0, NextSiblingSectionID = 2012, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 135817, Flags = 0, IconFlags = 0, DifficultyMask = -1};
EJ_EncounterSectionDB[2012] = { Title = "Fists of Frost", Desc = "Glubtok coats his fists with frost, causing each of his melee attacks that land to deal $87899s1 Frost damage. Additionally, when Glubtok lands a melee attack he will sometimes deal $87901s1 Frost damage, reduce the movement speed by $87901s2%, reduce the frequency of melee and ranged attacks by $87901s3%, and increase the casting time by $87901s3% of nearby enemies within $87901A1 yards for $87901d.", JournalEncounterID = 89, OrderIndex = 3, ParentSectionID = 2010, FirstChildSectionID = 0, NextSiblingSectionID = 2013, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 135785, Flags = 0, IconFlags = 0, DifficultyMask = -1};
EJ_EncounterSectionDB[2013] = { Title = "Blink", Desc = "After either Fists of Flame or Fists of Frost wears off, Glubtok will randomly teleport to a location nearby a random player.$[!2,4 In Heroic Difficulty, when Glubtok casts the Blink spell, he resets the threat of all enemies to zero.$]", JournalEncounterID = 89, OrderIndex = 4, ParentSectionID = 2010, FirstChildSectionID = 0, NextSiblingSectionID = 0, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 135736, Flags = 0, IconFlags = 0, DifficultyMask = -1};
EJ_EncounterSectionDB[2014] = { Title = "Stage Two: Arcane Power!", Desc = "At 50% health, Glubtok blinks to the center of the room and levitates in place. Glubtok then begins to cast Fire Blossom and Frost Blossom spells randomly throughout the room.", JournalEncounterID = 89, OrderIndex = 5, ParentSectionID = 0, FirstChildSectionID = 2015, NextSiblingSectionID = 0, Type = 0, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 1, IconFlags = 0, DifficultyMask = -1};
EJ_EncounterSectionDB[2015] = { Title = "Fire Blossom", Desc = "Glubtok launches a Fire Blossom at a random location in the room that lands two seconds later. When the Fire Blossom lands, it knocks up and inflicts $88173s1 Fire damage to nearby enemies within $88173A1 yards.$[!2,4 In Heroic Difficulty, wherever the spell lands, a Fire Blossom creature rises from the flames and begins to attack.$]", JournalEncounterID = 89, OrderIndex = 6, ParentSectionID = 2014, FirstChildSectionID = 2018, NextSiblingSectionID = 2016, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 135817, Flags = 0, IconFlags = 0, DifficultyMask = -1};
EJ_EncounterSectionDB[2016] = { Title = "Frost Blossom", Desc = "Glubtok launches a Frost Blossom at a random location in the room that lands two seconds later. When the Frost Blossom lands, it deals $88177s1 Frost damage, reduces the movement speed by $88177s2%, reduces the frequency of melee and ranged attacks by $88177s3%, and increases the casting time by $88177s3% of nearby enemies within $88177A1 yards for $88177d.$[!2,4 In Heroic Difficulty, wherever the spell lands a Frost Blossom creature forms from the ice and begins to attack.$]", JournalEncounterID = 89, OrderIndex = 8, ParentSectionID = 2014, FirstChildSectionID = 2019, NextSiblingSectionID = 2017, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 135785, Flags = 0, IconFlags = 0, DifficultyMask = -1};
EJ_EncounterSectionDB[2017] = { Title = "Fire Wall", Desc = "After casting Arcane Power, Glubtok creates a single wall of fire that begins to slowly rotate around him. Players who do not avoid the Fire Wall take $91397s1 Fire damage every second.", JournalEncounterID = 89, OrderIndex = 10, ParentSectionID = 2014, FirstChildSectionID = 0, NextSiblingSectionID = 0, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 135926, Flags = 2, IconFlags = 8, DifficultyMask = 14};
EJ_EncounterSectionDB[2018] = { Title = "Fire Blossom", Desc = "This elemental has very low health.", JournalEncounterID = 89, OrderIndex = 7, ParentSectionID = 2015, FirstChildSectionID = 0, NextSiblingSectionID = 0, Type = 1, IconCreatureDisplayInfoID = 4607, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 2, IconFlags = 8, DifficultyMask = 14};
EJ_EncounterSectionDB[2019] = { Title = "Frost Blossom", Desc = "This elemental has very low health.", JournalEncounterID = 89, OrderIndex = 9, ParentSectionID = 2016, FirstChildSectionID = 0, NextSiblingSectionID = 0, Type = 1, IconCreatureDisplayInfoID = 30160, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 2, IconFlags = 8, DifficultyMask = 14};
EJ_EncounterSectionDB[2020] = { Title = "Stage One: Bombs away!", Desc = "Helix Gearbreaker leaps onto the back of the Lumbering Oaf, and begins to order the Oaf around while throwing out Sticky Bombs.", JournalEncounterID = 90, OrderIndex = 1, ParentSectionID = 0, FirstChildSectionID = 2021, NextSiblingSectionID = 2026, Type = 0, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 1, IconFlags = 0, DifficultyMask = -1};
EJ_EncounterSectionDB[2021] = { Title = "Sticky Bomb", Desc = "Helix will periodically toss a Sticky Bomb onto the ground near a random player. After six seconds if the bomb detects a nearby player within one yard, the bomb explodes. A Sticky Bomb will also self destruct and explode if it is not triggered by a player after eighteen additional seconds. When a Sticky Bomb explodes, it knocks back and deals $88321s1 damage to enemy targets within $88321A1 yards.", JournalEncounterID = 90, OrderIndex = 2, ParentSectionID = 2020, FirstChildSectionID = 0, NextSiblingSectionID = 2022, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 136173, Flags = 0, IconFlags = 0, DifficultyMask = -1};
EJ_EncounterSectionDB[2022] = { Title = "Oaf Smash", Desc = "The Lumbering Oaf will periodically grab a player and run to the farthest side of the room from the entrance. The Oaf then quickly runs and smashes into a wooden log on the other side of the room, knocking back and dealing 100 Physical damage to the player.$[!2,4 In Heroic Difficulty, the impact of Oaf Smash instead inflicts $88300s2% of the target player's health in Physical damage. $]", JournalEncounterID = 90, OrderIndex = 3, ParentSectionID = 2020, FirstChildSectionID = 0, NextSiblingSectionID = 2023, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 132318, Flags = 0, IconFlags = 0, DifficultyMask = -1};
EJ_EncounterSectionDB[2023] = { Title = "Throw Helix", Desc = "The Lumbering Oaf will take Helix from his back, and throw the goblin onto a random player's face for ten seconds. While Helix is attached, he punches the player with his normal melee attack.", JournalEncounterID = 90, OrderIndex = 4, ParentSectionID = 2020, FirstChildSectionID = 0, NextSiblingSectionID = 2024, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 370769, Flags = 0, IconFlags = 0, DifficultyMask = -1};
EJ_EncounterSectionDB[2024] = { Title = "Chest Bomb", Desc = "When Helix leaps back onto the Lumbering Oaf after being attached to player, he leaves a Chest Bomb strapped to the player. After ten seconds, the Chest Bomb explodes. This explosion knocks the targeted player up very high, while dealing $88250s1 Fire damage to nearby player allies within $88250A1 yards.", JournalEncounterID = 90, OrderIndex = 5, ParentSectionID = 2020, FirstChildSectionID = 0, NextSiblingSectionID = 2025, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 133712, Flags = 2, IconFlags = 8, DifficultyMask = 14};
EJ_EncounterSectionDB[2025] = { Title = "Helix' Crew", Desc = "Four members of Helix' Crew appear above the players on an overhead log. Each crew member will periodically throw a Sticky Bomb onto the ground below near a random player.", JournalEncounterID = 90, OrderIndex = 6, ParentSectionID = 2020, FirstChildSectionID = 0, NextSiblingSectionID = 0, Type = 1, IconCreatureDisplayInfoID = 36379, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 2, IconFlags = 8, DifficultyMask = 14};
EJ_EncounterSectionDB[2026] = { Title = "Stage Two: I didn't need him!", Desc = "After the Lumbering Oaf dies, Helix Gearbreaker is thrown to the ground. Helix then uses his Sticky Bomb ability more frequently.", JournalEncounterID = 90, OrderIndex = 7, ParentSectionID = 0, FirstChildSectionID = 2027, NextSiblingSectionID = 0, Type = 0, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 1, IconFlags = 0, DifficultyMask = -1};
EJ_EncounterSectionDB[2027] = { Title = "Leap", Desc = "Helix will leap and attach himself to a player's face for ten seconds. Helix then immediately picks a new player and leaps on them. While Helix is attached, he punches the player with his normal melee attack.", JournalEncounterID = 90, OrderIndex = 8, ParentSectionID = 2026, FirstChildSectionID = 0, NextSiblingSectionID = 2028, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 370769, Flags = 0, IconFlags = 0, DifficultyMask = -1};
EJ_EncounterSectionDB[2028] = { Title = "Chest Bomb", Desc = "When Helix leaps off from a player, he leaves a Chest Bomb strapped to that player. After ten seconds, the Chest Bomb explodes. This explosion knocks the targeted player up very high, while dealing $88250s1 Fire damage to nearby player allies within $88250A1 yards.", JournalEncounterID = 90, OrderIndex = 9, ParentSectionID = 2026, FirstChildSectionID = 0, NextSiblingSectionID = 2029, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 133712, Flags = 2, IconFlags = 8, DifficultyMask = 14};
EJ_EncounterSectionDB[2029] = { Title = "Helix' Crew", Desc = "Four additional members of Helix' Crew appear above the players on an overhead log.", JournalEncounterID = 90, OrderIndex = 10, ParentSectionID = 2026, FirstChildSectionID = 0, NextSiblingSectionID = 0, Type = 1, IconCreatureDisplayInfoID = 36380, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 2, IconFlags = 8, DifficultyMask = 14};
EJ_EncounterSectionDB[2031] = { Title = "Reaper Strike", Desc = "The Foe Reaper 5000 does not have a normal melee attack. Instead, the Foe Reaper 5000 uses Reaper Strike, an attack dealing Physical damage to all targets within $88490A1 yards in a front facing 60 degree cone.", JournalEncounterID = 91, OrderIndex = 2, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 2032, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 236303, Flags = 0, IconFlags = 0, DifficultyMask = -1};
EJ_EncounterSectionDB[2032] = { Title = "Overdrive", Desc = "The Foe Reaper 5000 activates its overdrive engine, dealing $88484s1 Physical damage to nearby enemies every second for $88481d. After two seconds, the Foe Reaper 5000 also begins to wildly move around the room at double its normal movement speed.", JournalEncounterID = 91, OrderIndex = 3, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 2033, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 132369, Flags = 0, IconFlags = 0, DifficultyMask = -1};
EJ_EncounterSectionDB[2033] = { Title = "Harvest", Desc = "The Foe Reaper 5000 targets the location of a random player, and then moves there. As the Foe Reaper 5000 moves, it repeatedly deals $88501s1 Physical damage to all targets within $88501A1 yards in a front facing 60 degree cone. Once the Foe Reaper 5000 reaches the targeted location, it performs a Harvest Sweep attack. This attack knocks back and deals $88521s1 Physical damage to all nearby enemy targets within $88521A1 yards.", JournalEncounterID = 91, OrderIndex = 4, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 2034, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 132338, Flags = 0, IconFlags = 0, DifficultyMask = -1};
EJ_EncounterSectionDB[2034] = { Title = "Safety Restrictions Off-line", Desc = "When the Foe Reaper 5000 is damaged below 30% of its total health, it will disable its internal safety restrictions. This increases the Physical damage dealt by the Foe Reaper 5000 by $88522s1% for the remainder of the fight.", JournalEncounterID = 91, OrderIndex = 5, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 2035, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 135829, Flags = 0, IconFlags = 0, DifficultyMask = -1};
EJ_EncounterSectionDB[2035] = { Title = "Molten Slag", Desc = "Activation of the Foe Reaper 5000 causes an overload in the slag pit, resulting in Molten Slags periodically being spawned.", JournalEncounterID = 91, OrderIndex = 6, ParentSectionID = 0, FirstChildSectionID = 2036, NextSiblingSectionID = 2038, Type = 1, IconCreatureDisplayInfoID = 36419, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 2, IconFlags = 8, DifficultyMask = 14};
EJ_EncounterSectionDB[2036] = { Title = "Fixate", Desc = "A Molten Slag will periodically fixate on a random enemy target, moving to attack only that target for $91830d.", JournalEncounterID = 91, OrderIndex = 7, ParentSectionID = 2035, FirstChildSectionID = 0, NextSiblingSectionID = 2037, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 136088, Flags = 2, IconFlags = 0, DifficultyMask = 14};
EJ_EncounterSectionDB[2037] = { Title = "Molten Shield", Desc = "A Molten Slag only takes 50% damage from magical sources, and will deal $91819s1 Fire damage to all nearby targets within $91819A1 yards every $91815t2 sec.", JournalEncounterID = 91, OrderIndex = 8, ParentSectionID = 2035, FirstChildSectionID = 0, NextSiblingSectionID = 0, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 135818, Flags = 2, IconFlags = 0, DifficultyMask = 14};
EJ_EncounterSectionDB[2038] = { Title = "Prototype Reaper", Desc = "A single Prototype Reaper was left unattended in the Defias workers' mad dash to flee the Goblin Foundry. One player may board the Prototype Reaper and use it in the fight against the Foe Reaper 5000. The abilities of the Prototype Reaper are powered by steam.", JournalEncounterID = 91, OrderIndex = 9, ParentSectionID = 0, FirstChildSectionID = 2039, NextSiblingSectionID = 0, Type = 1, IconCreatureDisplayInfoID = 36412, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 2, IconFlags = 8, DifficultyMask = 14};
EJ_EncounterSectionDB[2039] = { Title = "Obsidian Alloy", Desc = "The Prototype Reaper is immune to Fire damage.", JournalEncounterID = 91, OrderIndex = 10, ParentSectionID = 2038, FirstChildSectionID = 0, NextSiblingSectionID = 2040, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 132360, Flags = 2, IconFlags = 0, DifficultyMask = 14};
EJ_EncounterSectionDB[2040] = { Title = "Reaper Strike", Desc = "The Prototype Reaper deals $91723s1 Physical damage to all targets within $91723A1 yards in a front facing 60 degree cone. Reaper Strike also grants the Prototype Reaper $91723s2 steam power.", JournalEncounterID = 91, OrderIndex = 11, ParentSectionID = 2038, FirstChildSectionID = 0, NextSiblingSectionID = 2041, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 236303, Flags = 2, IconFlags = 0, DifficultyMask = 14};
EJ_EncounterSectionDB[2041] = { Title = "Reaper Charge", Desc = "The Prototype Reaper charges an enemy target, dealing $91726s2 Physical damage and stunning the target for $91726d. Reaper Charge costs $91726c steam power.", JournalEncounterID = 91, OrderIndex = 12, ParentSectionID = 2038, FirstChildSectionID = 0, NextSiblingSectionID = 2042, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 132337, Flags = 2, IconFlags = 0, DifficultyMask = 14};
EJ_EncounterSectionDB[2042] = { Title = "Pressurized Strike", Desc = "Steam pressure is released into a powerful attack on an enemy target, dealing $91727s2 Physical damage and knocking the target back. Pressurized Strike costs $91727c steam power.", JournalEncounterID = 91, OrderIndex = 13, ParentSectionID = 2038, FirstChildSectionID = 0, NextSiblingSectionID = 0, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 135906, Flags = 2, IconFlags = 0, DifficultyMask = 14};
EJ_EncounterSectionDB[2044] = { Title = "Thirst for Blood", Desc = "Whenever Admiral Ripsnarl lands a successful melee attack, he gains $88737s1% attack speed, $88737s3% movement speed, and grows by $88737s2% for $88737d. This effect may stack up to 20 times.", JournalEncounterID = 92, OrderIndex = 1, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 2045, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 132334, Flags = 0, IconFlags = 0, DifficultyMask = -1};
EJ_EncounterSectionDB[2045] = { Title = "Swipe", Desc = "Admiral Ripsnarl ferociously swipes his primary target and two other nearby targets in melee range for $88839s1% of the damage of his normal melee attack.", JournalEncounterID = 92, OrderIndex = 2, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 2046, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 134296, Flags = 0, IconFlags = 0, DifficultyMask = -1};
EJ_EncounterSectionDB[2046] = { Title = "The Fog", Desc = "When Admiral Ripsnarl reaches 75%, 50%, and 25% health, he retreats into the fog and becomes unattackable for a short time.", JournalEncounterID = 92, OrderIndex = 3, ParentSectionID = 0, FirstChildSectionID = 2047, NextSiblingSectionID = 0, Type = 0, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 1, IconFlags = 0, DifficultyMask = -1};
EJ_EncounterSectionDB[2047] = { Title = "Go For the Throat", Desc = "When Admiral Ripsnarl reveals himself once more from the fog, he leaps at a random enemy dealing $88836s2% of a normal melee attack's damage and stunning the target for $88836d.$[!2,4 In Heroic Difficulty, Admiral Ripsnarl will use Go For the Throat during the entire encounter.$]", JournalEncounterID = 92, OrderIndex = 4, ParentSectionID = 2046, FirstChildSectionID = 0, NextSiblingSectionID = 2048, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 132337, Flags = 0, IconFlags = 0, DifficultyMask = -1};
EJ_EncounterSectionDB[2048] = { Title = "Summon Vapor", Desc = "After the fog rolls in over the deck, Vapor creatures periodically form and attack a nearby player. Whenever Admiral Ripsnarl vanishes into the fog, additional Vapor creatures are created.$[!2,4  In Heroic Difficulty, When Admiral Ripsnarl is damaged below 10% health, three additional Vapor creatures form from the fog.$]", JournalEncounterID = 92, OrderIndex = 5, ParentSectionID = 2046, FirstChildSectionID = 0, NextSiblingSectionID = 2049, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 135861, Flags = 0, IconFlags = 0, DifficultyMask = -1};
EJ_EncounterSectionDB[2049] = { Title = "Vapor", Desc = "This creature attacks from the fog.", JournalEncounterID = 92, OrderIndex = 6, ParentSectionID = 2046, FirstChildSectionID = 2050, NextSiblingSectionID = 0, Type = 1, IconCreatureDisplayInfoID = 35786, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 0, IconFlags = 0, DifficultyMask = -1};
EJ_EncounterSectionDB[2050] = { Title = "Condensation", Desc = "After a Vapor forms, condensation from the moisture in the fog begins to cause the Vapor to grow. If the Vapor is not destroyed within 8 seconds, the Vapor transforms into a Swirling Vapor with its health increased by $92017s2% and damage dealt increased by $92017s3%. If Swirling Vapor is not destroyed in another 8 seconds, it transforms into a Condensed Vapor with its health increased by $92021s2% and damage dealt increased by $92021s3%. If a Condensed Vapor is then not destroyed within 8 more seconds, it finally transforms into a Freezing Vapor with its health increased by $92038s2% and damage dealt increased by $92038s3%.", JournalEncounterID = 92, OrderIndex = 7, ParentSectionID = 2049, FirstChildSectionID = 0, NextSiblingSectionID = 2051, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 135833, Flags = 2, IconFlags = 32, DifficultyMask = -2};
EJ_EncounterSectionDB[2051] = { Title = "Swirling Vapor", Desc = "When a Vapor transforms into Swirling Vapor, it gains the ability to cast a spell of the same name. Swirling Vapor deals $92007s2 Frost damage and reduces the movement speed by $92007s1% of all targets within $92007A1 yards in a front facing 60 degree cone for $92007d.", JournalEncounterID = 92, OrderIndex = 8, ParentSectionID = 2049, FirstChildSectionID = 0, NextSiblingSectionID = 2052, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 135852, Flags = 2, IconFlags = 0, DifficultyMask = -2};
EJ_EncounterSectionDB[2052] = { Title = "Condensing Vapor", Desc = "When a Swirling Vapor transforms into Condensing Vapor, it gains the ability to cast a spell of the same name. Condensing Vapor deals $92008s2 Frost damage and reduces the movement speed by $92008s1% of all targets within $92008A1 yards in a front facing 60 degree cone for $92007d.", JournalEncounterID = 92, OrderIndex = 9, ParentSectionID = 2049, FirstChildSectionID = 0, NextSiblingSectionID = 2053, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 135852, Flags = 2, IconFlags = 0, DifficultyMask = -2};
EJ_EncounterSectionDB[2053] = { Title = "Coalesce", Desc = "When a Vapor fully transforms into a Freezing Vapor, it will then explode dealing $92042s2 Frost damage and knocking back all enemy targets within $92042A1 yards.", JournalEncounterID = 92, OrderIndex = 10, ParentSectionID = 2049, FirstChildSectionID = 0, NextSiblingSectionID = 0, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 135863, Flags = 2, IconFlags = 0, DifficultyMask = -2};
EJ_EncounterSectionDB[2055] = { Title = "Throw Food", Desc = "Captain\" Cookie will rapidly throw food at the location of a random player, alternating between delicious and rotten food items.", JournalEncounterID = 93, OrderIndex = 1, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 2056, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 350571, Flags = 0, IconFlags = 0, DifficultyMask = -1};
EJ_EncounterSectionDB[2056] = { Title = "Rotten Aura", Desc = "Rotten food on the ground emanates $89735s1 Nature damage to nearby units within $89735A1 yards.", JournalEncounterID = 93, OrderIndex = 2, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 2057, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 237334, Flags = 0, IconFlags = 0, DifficultyMask = -1};
EJ_EncounterSectionDB[2057] = { Title = "Nauseated", Desc = "Players may right click on and eat the rotten food found on the deck. This removes the food and its corresponding Rotten Aura from the deck, but inflicts the Nauseated effect on the player dealing $89732s2 Nature damage every $89732t2 sec. for $89732d. The Nauseated effect stacks.", JournalEncounterID = 93, OrderIndex = 3, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 2058, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 237555, Flags = 0, IconFlags = 0, DifficultyMask = -1};
EJ_EncounterSectionDB[2058] = { Title = "Satiated", Desc = "Players may right click on and eat the delicious food found on the deck. This removes the food from the deck, but the clicking player gains the Satiated effect. Satiated increases the melee and ranged attack speed, as well as spell casting speed of the player by $89267s2% for $89267d. The Satiated effect stacks.  Each time the Satiated effect is gained, a single stack of the Nauseated effect is removed.", JournalEncounterID = 93, OrderIndex = 4, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 0, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 237554, Flags = 0, IconFlags = 0, DifficultyMask = -1};
EJ_EncounterSectionDB[2060] = { Title = "Deflection", Desc = "Vanessa deflects all melee attacks, ranged attacks and spells for $92615d. She will only use this ability while her remaining health is greater than 25%.", JournalEncounterID = 95, OrderIndex = 1, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 2061, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 132369, Flags = 2, IconFlags = 0, DifficultyMask = 14};
EJ_EncounterSectionDB[2061] = { Title = "Deadly Blades", Desc = "Vanessa begins to rapidly leap from enemy to enemy, appearing behind and inflicting the Backslash effect on a random enemy target every $92622t1 sec. for $92622d.", JournalEncounterID = 95, OrderIndex = 2, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 2062, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 135639, Flags = 2, IconFlags = 0, DifficultyMask = 14};
EJ_EncounterSectionDB[2062] = { Title = "Backslash", Desc = "Vanessa slices into the back of an enemy target, inflicting $92619s2 Physical damage every $92619t2 seconds for $92619d.", JournalEncounterID = 95, OrderIndex = 3, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 2063, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 132303, Flags = 2, IconFlags = 0, DifficultyMask = 14};
EJ_EncounterSectionDB[2063] = { Title = "Fiery Blaze", Desc = "After Vanessa has been wounded below 50% of her total health, she will leap to the top of the ship and detonate preplaced explosives around the ship. These explosives will create Fiery Blazes across the deck. Players within $93485A1 yards of a fire will be dealt $93485s1 Fire damage every second.  Players may avoid the worst of the fires on the deck by using a nearby rope on the side of the deck.", JournalEncounterID = 95, OrderIndex = 4, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 2064, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 135826, Flags = 2, IconFlags = 16, DifficultyMask = 14};
EJ_EncounterSectionDB[2064] = { Title = "Vengeance of VanCleef", Desc = "After Vanessa detonates the first set of explosives at 50% health, she will repeatedly cast Vengeance of VanCleef until re-engaged in combat.  Each application of this effect increases her Physical damage by $95542s1%, melee attack speed by $95542s2%, and size by $95542s3%. The effect may stack up to 40 times. Once Vanessa has detonated the second set of explosives at 25% health, she will use this ability repeatedly until killed.", JournalEncounterID = 95, OrderIndex = 5, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 2065, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 236409, Flags = 2, IconFlags = 0, DifficultyMask = 14};
EJ_EncounterSectionDB[2065] = { Title = "Powder Explosion", Desc = "When Vanessa has only 1% of her total health remaining, she will pull out a final keg of black powder and light it. The explosion kills her, and also deals $96283s2 Fire damage to any enemy target within $96283A2 yards.", JournalEncounterID = 95, OrderIndex = 6, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 2066, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 236216, Flags = 2, IconFlags = 16, DifficultyMask = 14};
EJ_EncounterSectionDB[2066] = { Title = "Defias Enforcer", Desc = "While Vanessa VanCleef's remaining health is above 50%, she will periodically call on a Defias Enforcer to aid her from the nearby cabin.", JournalEncounterID = 95, OrderIndex = 7, ParentSectionID = 0, FirstChildSectionID = 2067, NextSiblingSectionID = 2070, Type = 1, IconCreatureDisplayInfoID = 36166, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 2, IconFlags = 0, DifficultyMask = 14};
EJ_EncounterSectionDB[2067] = { Title = "Charge", Desc = "The Enforcer charges out into battle to join the fray.", JournalEncounterID = 95, OrderIndex = 8, ParentSectionID = 2066, FirstChildSectionID = 0, NextSiblingSectionID = 2068, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 132337, Flags = 2, IconFlags = 0, DifficultyMask = 14};
EJ_EncounterSectionDB[2068] = { Title = "Bloodbath", Desc = "The Enforcer begins to rapidly attack its current enemy target with a series of six quick attacks over $90925d., each dealing $90923s1% of normal melee damage.", JournalEncounterID = 95, OrderIndex = 9, ParentSectionID = 2066, FirstChildSectionID = 0, NextSiblingSectionID = 2069, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 136124, Flags = 2, IconFlags = 0, DifficultyMask = 14};
EJ_EncounterSectionDB[2069] = { Title = "Recklessness", Desc = "The Enforcer becomes immune to fear effects and his or her chance to deal a critical is increased by $90929s1% for $90929d., but the Enforcer's armor is also reduced by $90929s2%. The Enforcer can use this ability if his or her remaining health is below 20%.", JournalEncounterID = 95, OrderIndex = 10, ParentSectionID = 2066, FirstChildSectionID = 0, NextSiblingSectionID = 0, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 132109, Flags = 2, IconFlags = 0, DifficultyMask = 14};
EJ_EncounterSectionDB[2070] = { Title = "Defias Shadowguard", Desc = "Shortly after calling a Defias Enforcer, Vanessa will then call on a Defias Shadowguard to join the fight if her remaining health is still above 50%.", JournalEncounterID = 95, OrderIndex = 11, ParentSectionID = 0, FirstChildSectionID = 2071, NextSiblingSectionID = 2075, Type = 1, IconCreatureDisplayInfoID = 184, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 2, IconFlags = 0, DifficultyMask = 14};
EJ_EncounterSectionDB[2071] = { Title = "Sinister Strike", Desc = "The Shadowguard inflicts $90951s1% of normal melee damage to the current enemy target.", JournalEncounterID = 95, OrderIndex = 12, ParentSectionID = 2070, FirstChildSectionID = 0, NextSiblingSectionID = 2072, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 136189, Flags = 2, IconFlags = 0, DifficultyMask = 14};
EJ_EncounterSectionDB[2072] = { Title = "Shadowstep", Desc = "The Shadowguard will periodically step through shadows and reappear behind the enemy target.", JournalEncounterID = 95, OrderIndex = 13, ParentSectionID = 2070, FirstChildSectionID = 0, NextSiblingSectionID = 2073, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 132303, Flags = 2, IconFlags = 0, DifficultyMask = 14};
EJ_EncounterSectionDB[2073] = { Title = "Whirling Blades", Desc = "The Shadowguard surrounds the enemy target with a set of whirling blades for $90960d. The blades deal $90962s1 Physical damage to all nearby units within $90962A1 yards every second.", JournalEncounterID = 95, OrderIndex = 14, ParentSectionID = 2070, FirstChildSectionID = 0, NextSiblingSectionID = 2074, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 236273, Flags = 2, IconFlags = 0, DifficultyMask = 14};
EJ_EncounterSectionDB[2074] = { Title = "Evasion", Desc = "The Shadowguard increases his chance to dodge by $90958s1% for $90958d.  The Shadowguard may use Evasion if his remaining health is below 30%.", JournalEncounterID = 95, OrderIndex = 15, ParentSectionID = 2070, FirstChildSectionID = 0, NextSiblingSectionID = 0, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 136205, Flags = 2, IconFlags = 0, DifficultyMask = 14};
EJ_EncounterSectionDB[2075] = { Title = "Defias Blood Wizard", Desc = "Shortly after calling a Defias Shadowguard, Vanessa will then call on a Defias Blood Wizard to join the fight if her remaining health is still above 50%.", JournalEncounterID = 95, OrderIndex = 16, ParentSectionID = 0, FirstChildSectionID = 2076, NextSiblingSectionID = 3585, Type = 1, IconCreatureDisplayInfoID = 2448, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 2, IconFlags = 0, DifficultyMask = 14};
EJ_EncounterSectionDB[2076] = { Title = "Bloodbolt", Desc = "Inflicts $90938s1 Physical damage and reduces the current enemy target's movement speed by $90938s2% for $90938d.", JournalEncounterID = 95, OrderIndex = 17, ParentSectionID = 2075, FirstChildSectionID = 0, NextSiblingSectionID = 2077, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 136168, Flags = 2, IconFlags = 0, DifficultyMask = 14};
EJ_EncounterSectionDB[2077] = { Title = "Ragezone", Desc = "The Blood Wizard creates an unstable field of magic at the location of a random enemy target that lasts $90932d. The field has a radius of $90932A1 yards, and all units located within have their damage dealt increased by $90932s2%.", JournalEncounterID = 95, OrderIndex = 18, ParentSectionID = 2075, FirstChildSectionID = 0, NextSiblingSectionID = 0, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 136088, Flags = 2, IconFlags = 0, DifficultyMask = 14};
EJ_EncounterSectionDB[2107] = { Title = "Asphyxiate", Desc = "Baron Ashbury throws every player into the air, stunning them and dealing enough Shadow damage over $93423d. to bring the player's health to one.", JournalEncounterID = 96, OrderIndex = 1, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 2108, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 237532, Flags = 0, IconFlags = 0, DifficultyMask = -1};
EJ_EncounterSectionDB[2108] = { Title = "Stay of Execution", Desc = "After Baron Ashbury finishes casting Asphyxiate, he immediately casts Stay of Execution. This spell heals all players to 50% of their maximum health.$[!2,4 In Heroic Difficulty, instead of healing players at the end of the cast, Baron Ashbury channels Stay of Execution until interrupted. Players are healed every second for $93706s1% of their maximum health, but Baron Ashbury is also healed for $93706s2% of his maximum health.$]", JournalEncounterID = 96, OrderIndex = 2, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 2109, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 135917, Flags = 0, IconFlags = 96, DifficultyMask = -1};
EJ_EncounterSectionDB[2109] = { Title = "Pain and Suffering", Desc = "Baron Ashbury channels on a random player, initially dealing $93581s1 Shadow damage every $93581t1 second for $93581d. The damage dealt increases as the spell continues to channel.", JournalEncounterID = 96, OrderIndex = 3, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 3457, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 136207, Flags = 0, IconFlags = 128, DifficultyMask = -1};
EJ_EncounterSectionDB[2110] = { Title = "Calamity", Desc = "At 25% health, Baron Ashbury takes the form of a Dark Archangel and unleashes his true power. Baron Ashbury inflicts $93810s1 Shadow damage and increases the Shadow damage enemies take by $93810s2% every $93812t1 second until either Baron Ashbury or his enemies die. This effect stacks.", JournalEncounterID = 96, OrderIndex = 5, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 0, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 237514, Flags = 2, IconFlags = 8, DifficultyMask = 14};
