EJ_EncounterSectionDB[2120] = { Title = "Summon Worgen Spirit", Desc = "Baron Silverlaine summons one of four random Worgen Spirits from the past at 70% and 35% health: Odo the Blindwatcher, Razorclaw the Butcher, Rethilgore, or Wolf Master Nandos.$[!2,4 In Heroic Difficulty, Baron Silverlaine summons a Worgen Spirit at 90%, 60%, and 30% health.$]", JournalEncounterID = 97, OrderIndex = 3, ParentSectionID = 0, FirstChildSectionID = 2121, NextSiblingSectionID = 0, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 366940, Flags = 1, IconFlags = 32, DifficultyMask = -1};
