EJ_EncounterSectionDB[2132] = { Title = "Summon Lupine Spirit", Desc = "When Wolf Master Nandos enters combat, he summons three Lupine Spectres to fight at his side for $94199d.", JournalEncounterID = 97, OrderIndex = 14, ParentSectionID = 2130, FirstChildSectionID = 2133, NextSiblingSectionID = 0, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 366940, Flags = 0, IconFlags = 0, DifficultyMask = -1};
