EJ_EncounterSectionDB[2137] = { Title = "Malefic Strike", Desc = "Commander Springvale slashes at his main target, instantly dealing $93685s1% of his normal Physical melee damage and generating a charge of Unholy Power he can then use for other abilities.", JournalEncounterID = 98, OrderIndex = 1, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 2138, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 237530, Flags = 0, IconFlags = 0, DifficultyMask = -1};
EJ_EncounterSectionDB[2138] = { Title = "Shield of the Perfidious", Desc = "When Commander Springvale has three charges of Unholy Power, he consumes the charges and unleashes the power from his shield. Shield of the Perfidious deals $93722s1 Shadow damage every $93693t1 seconds in a narrow 25 degree cone in front of Springvale for $93693d. $[!2,4 In Heroic Difficulty, the cone expands to 150 degrees.$]", JournalEncounterID = 98, OrderIndex = 2, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 2139, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 132390, Flags = 0, IconFlags = 0, DifficultyMask = -1};
EJ_EncounterSectionDB[2139] = { Title = "Desecration", Desc = "Commander Springvale desecrates the ground in a $93691A1 yard radius under a random player. All players standing in this defiled ground have their movement speed decreased by $93691s1% and take $93691s2 Shadow damage every $93690t1 seconds.", JournalEncounterID = 98, OrderIndex = 3, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 2140, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 136199, Flags = 0, IconFlags = 0, DifficultyMask = -1};
EJ_EncounterSectionDB[2140] = { Title = "Word of Shame", Desc = "When Commander Springvale has three charges of Unholy Power, he can consume the charges and cast this spell on a random enemy player. Word of Shame deals $93852s1% of a player's maximum health as Shadow damage every $93852t1 seconds. The effect lasts until either the targeted player or Commander Springvale dies.", JournalEncounterID = 98, OrderIndex = 4, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 2142, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 237555, Flags = 2, IconFlags = 8, DifficultyMask = 2};
EJ_EncounterSectionDB[2142] = { Title = "Wailing Guardsman", Desc = "Commander Springvale starts with a Wailing Guardsman and Tormented Officer next to him, and periodically two more will enter the fray.", JournalEncounterID = 98, OrderIndex = 5, ParentSectionID = 0, FirstChildSectionID = 2143, NextSiblingSectionID = 2146, Type = 1, IconCreatureDisplayInfoID = 37289, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 2, IconFlags = 8, DifficultyMask = 2};
EJ_EncounterSectionDB[2143] = { Title = "Unholy Empowerment", Desc = "A Wailing Guardsman attempts to empower Commander Springvale. If the spell is successfully cast, Commander Springvale is healed for $93844s2% of his maximum health and gains one charge of Unholy Power.", JournalEncounterID = 98, OrderIndex = 6, ParentSectionID = 2142, FirstChildSectionID = 0, NextSiblingSectionID = 2144, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 136194, Flags = 2, IconFlags = 64, DifficultyMask = 2};
EJ_EncounterSectionDB[2144] = { Title = "Screams of the Past", Desc = "The Wailing Guardman emits a terrible scream, interrupting nearby enemy spellcasting within $7074A1 yards. Interrupted enemies cannot cast spells of the same spell school for $7074d.", JournalEncounterID = 98, OrderIndex = 7, ParentSectionID = 2142, FirstChildSectionID = 0, NextSiblingSectionID = 2145, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 136164, Flags = 2, IconFlags = 0, DifficultyMask = 2};
EJ_EncounterSectionDB[2145] = { Title = "Mortal Strike", Desc = "The Wailing Guardsman instantly attacks his enemy, inflicting $91801s1% of their normal weapon damage and leaving the enemy wounded. This mortal wound reduces the effectiveness of any healing on the target by $91801s2%.", JournalEncounterID = 98, OrderIndex = 8, ParentSectionID = 2142, FirstChildSectionID = 0, NextSiblingSectionID = 0, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 132355, Flags = 2, IconFlags = 0, DifficultyMask = 2};
EJ_EncounterSectionDB[2146] = { Title = "Tormented Officer", Desc = "Commander Springvale starts with a Wailing Guardsman and Tormented Officer next to him, and periodically two more will enter the fray.", JournalEncounterID = 98, OrderIndex = 9, ParentSectionID = 0, FirstChildSectionID = 2147, NextSiblingSectionID = 0, Type = 1, IconCreatureDisplayInfoID = 37294, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 2, IconFlags = 8, DifficultyMask = 2};
EJ_EncounterSectionDB[2147] = { Title = "Unholy Empowerment", Desc = "A Tormented Officer attempts to empower Commander Springvale. If the spell is successfully cast, Commander Springvale is healed for $93844s2% of his maximum health and gains one charge of Unholy Power.", JournalEncounterID = 98, OrderIndex = 10, ParentSectionID = 2146, FirstChildSectionID = 0, NextSiblingSectionID = 2148, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 136194, Flags = 2, IconFlags = 64, DifficultyMask = 2};
EJ_EncounterSectionDB[2148] = { Title = "Shield Wall", Desc = "When a Tormented Officer is below 20% health, he will raise his shield defensively. This reduces all damage taken by $91463s1% for $91463d.", JournalEncounterID = 98, OrderIndex = 11, ParentSectionID = 2146, FirstChildSectionID = 0, NextSiblingSectionID = 2149, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 132362, Flags = 2, IconFlags = 0, DifficultyMask = 2};
EJ_EncounterSectionDB[2149] = { Title = "Forsaken Ability", Desc = "The Tormented Officer curses an enemy target for $7054d. While the curse is on the enemy, every $7054t1 seconds an additional random curse is applied. The additional curses lasts $7039d., and will reduce by $7039s1% one of the following: armor, damage dealt, healing dealt, maximum health, or movement speed.", JournalEncounterID = 98, OrderIndex = 12, ParentSectionID = 2146, FirstChildSectionID = 0, NextSiblingSectionID = 0, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 136121, Flags = 2, IconFlags = 320, DifficultyMask = 2};
EJ_EncounterSectionDB[2156] = { Title = "Ice Shards", Desc = "Lord Walden releases Ice Shards all over his laboratory for $93527d. Each Ice Shard arcs through the air then lands, dealing $93535s1 Frost damage to all enemy targets within $93535A1 yards.", JournalEncounterID = 99, OrderIndex = 1, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 2157, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 237236, Flags = 0, IconFlags = 0, DifficultyMask = -1};
EJ_EncounterSectionDB[2157] = { Title = "Conjure Poisonous Mixture", Desc = "Lord Walden conjures a bottle of poisonous mixture then throws it at the location of a random player. When the bottle lands on the ground it erupts.  The poison immediately inflicts $93697s1 Nature damage to players within $93697A1 yards, and continues to inflict $93697s2 Nature damage every $93697t2 seconds while decreasing the movement speed of players by $93697s3% for $93697d.", JournalEncounterID = 99, OrderIndex = 2, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 2392, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 136242, Flags = 2, IconFlags = 0, DifficultyMask = 1};
EJ_EncounterSectionDB[2158] = { Title = "Conjure Frost Mixture", Desc = "Lord Walden summons a frosty mixture and breaks it on the ground. The chemicals immediately deal $93505s1 Frost damage to all nearby enemies within $93505A1 yards.", JournalEncounterID = 99, OrderIndex = 4, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 2159, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 135851, Flags = 0, IconFlags = 0, DifficultyMask = -1};
EJ_EncounterSectionDB[2159] = { Title = "Conjure Mystery Toxin", Desc = "Lord Walden summons a cauldron of Mystery Toxin for 10 seconds. The concoction inside is usually a Toxic Coagulant, but when Lord Walden reaches 35% health he summons a cauldron of Toxic Catalyst instead.", JournalEncounterID = 99, OrderIndex = 5, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 2160, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 134400, Flags = 2, IconFlags = 8, DifficultyMask = 2};
EJ_EncounterSectionDB[2160] = { Title = "Toxic Coagulent", Desc = "Every $93572t1 seconds the Toxic Coagulent toxin is applied to nearby enemy players from Lord Walden's cauldron. The Toxic Coagulent inflicts $93617s2 damage every second, and decreases the movement speed of the affected player by $93617s3% for $93617d.  This effect can stack up to 3 times, and if it does then the toxin fully coagulates and the player is stunned for $93660d. However, whenever a player moves or jumps the toxin becomes unable to coagulate and a stack is removed.", JournalEncounterID = 99, OrderIndex = 6, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 2161, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 348567, Flags = 2, IconFlags = 8, DifficultyMask = 2};
EJ_EncounterSectionDB[2161] = { Title = "Toxic Catalyst", Desc = "The Toxic Catalyst pours out of Lord Walden's cauldron, inflicting $93689s1 Fire damage every $93689t1 seconds but increasing the target's critical chance by $93689s2% for $93689d.", JournalEncounterID = 99, OrderIndex = 7, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 0, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 132847, Flags = 2, IconFlags = 8, DifficultyMask = 2};
EJ_EncounterSectionDB[2163] = { Title = "Mortal Wound", Desc = "Lord Godfrey slices his current target with the blades attached to his pistols, inflicting $93675s1 Physical damage every second and reducing the effectiveness of healing dealt to the target by $93675s2% for $93675d. This effect stacks up to 10 times.", JournalEncounterID = 100, OrderIndex = 3, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 2165, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 132109, Flags = 0, IconFlags = 0, DifficultyMask = -1};
EJ_EncounterSectionDB[2164] = { Title = "Cursed Bullets", Desc = "Lord Godfrey picks a random player and shoots them with cursed bullets. This attack immediately deals $93629s1 Shadow damage to the target, and continues to deal severe and increasing Shadow damage every $93629t2 seconds for $93629d.", JournalEncounterID = 100, OrderIndex = 1, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 2167, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 136181, Flags = 0, IconFlags = 320, DifficultyMask = -1};
