EJ_EncounterSectionDB[2167] = { Title = "Pistol Barrage", Desc = "Lord Godfrey points at a random player and unleashes a barrage of bullets in a 60 degree cone towards that direction from his pair of pistols for $93520d. The Pistol Barrage deals $93564s1 Shadow damage every second to any unit within the cone of bullets.", JournalEncounterID = 100, OrderIndex = 2, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 2163, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 377283, Flags = 2, IconFlags = 8, DifficultyMask = 2};
