EJ_EncounterSectionDB[2496] = { Title = "Sleep", Desc = "When Hazza'rah reaches 66% and 33% remaining health, Hazza'rah places all but one random enemy player to sleep for $96654d. Hazza'rah then awakens a Nightmare within each sleeping player, creating a Nightmare Illusion that begins to walk towards the target.", JournalEncounterID = 178, OrderIndex = 3, ParentSectionID = 0, FirstChildSectionID = 2497, NextSiblingSectionID = 3340, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 136090, Flags = 3, IconFlags = 32, DifficultyMask = -2};
