EJ_EncounterSectionDB[2498] = { Title = "Lightning Cloud", Desc = "Wushoolay conjures a $96710A1 yard radius Lightning Cloud over a random player, immediately inflicting $96710s1 Nature damage to players under the cloud. The cloud also inflicts $96710s2 additional Nature damage every $96710t2 sec., and lasts for $96710d.", JournalEncounterID = 180, OrderIndex = 1, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 2499, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 136014, Flags = 2, IconFlags = 0, DifficultyMask = -2};
