EJ_EncounterSectionDB[2525] = { Title = "Electrical Storm", Desc = "Akil'zon immobilizes a random player in midair and creates a massive electrical storm for $43648d. Players within 20 yards of the immobilized player are safe from the storm. Every second a player stands outside this safe distance, the storm inflicts $43657s1 Nature damage and increases Nature damage taken by $43657s2% for $43657d.", JournalEncounterID = 186, OrderIndex = 7, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 3346, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 135990, Flags = 2, IconFlags = 0, DifficultyMask = -2};
