EJ_EncounterSectionDB[2616] = { Title = "Ohgan's Orders", Desc = "Bloodlord Mandokir dismounts from Ohgan and instructs him to kill the Chained Spirits in the area.  If Ohgan reaches a Chained Spirit, he kills it and acquires a new Chained Spirit as his target.", JournalEncounterID = 176, OrderIndex = 7, ParentSectionID = 2615, FirstChildSectionID = 0, NextSiblingSectionID = 2617, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 456563, Flags = 2, IconFlags = 0, DifficultyMask = 14};
EJ_EncounterSectionDB[2617] = { Title = "Reanimate Ohgan", Desc = "Bloodlord Mandokir resurrects Ohgan after the players kill the raptor. Ohgan resumes his Orders from when he was alive.", JournalEncounterID = 176, OrderIndex = 8, ParentSectionID = 2615, FirstChildSectionID = 0, NextSiblingSectionID = 0, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 456563, Flags = 2, IconFlags = 0, DifficultyMask = 14};
EJ_EncounterSectionDB[2618] = { Title = "Chained Spirit", Desc = "Eight Chained Spirits stand ready to aid the players against Bloodlord Mandokir. Chained Spirits perform Revive on dead players during the fight.", JournalEncounterID = 176, OrderIndex = 9, ParentSectionID = 0, FirstChildSectionID = 2619, NextSiblingSectionID = 3338, Type = 1, IconCreatureDisplayInfoID = 37794, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 3, IconFlags = 32, DifficultyMask = 14};
EJ_EncounterSectionDB[2619] = { Title = "Revive", Desc = "Chained Spirits periodically bring dead players back to life and then empower them with Spirit's Vengeance.", JournalEncounterID = 176, OrderIndex = 10, ParentSectionID = 2618, FirstChildSectionID = 0, NextSiblingSectionID = 2620, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 135955, Flags = 2, IconFlags = 0, DifficultyMask = 14};
EJ_EncounterSectionDB[2620] = { Title = "Spirit's Vengeance", Desc = "The Chained Spirit empowers the newly Revived player, increasing damage and healing done by $96493s2%, maximum health by $96494s1%, and decreasing all damage taken by $96494s2% for the duration of the fight. This effect stacks.", JournalEncounterID = 176, OrderIndex = 11, ParentSectionID = 2618, FirstChildSectionID = 0, NextSiblingSectionID = 0, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 135898, Flags = 2, IconFlags = 0, DifficultyMask = 14};
EJ_EncounterSectionDB[2621] = { Title = "Flame Breath", Desc = "Jan'alai chooses a random player, then turns and casts Flame Breath in their direction. The Flame Breath inflicts $97495s3 Fire damage to all enemies in a frontal 60 degree cone from Jan'alai.  The Flame Breath also leaves a line of fire that inflicts $97497s1 Fire damage every $97497t1 sec. to enemies within $97497A1 yards of the path of flame.", JournalEncounterID = 188, OrderIndex = 1, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 2622, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 135805, Flags = 2, IconFlags = 0, DifficultyMask = -2};
EJ_EncounterSectionDB[2622] = { Title = "Fire Bomb", Desc = "Jan'alai teleports to the middle of the platform and creates Fire Bombs around the platform. After five seconds Jan'alai detonates the Fire Bombs, inflicting $42630s1 Fire damage to players within $42630A1 yards of a Fire Bomb.", JournalEncounterID = 188, OrderIndex = 2, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 2623, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 135789, Flags = 2, IconFlags = 0, DifficultyMask = -2};
