EJ_EncounterSectionDB[2791] = { Title = "Stage Two: The Mortal Coil Unwinds", Desc = "After a set period of time, High Priest Venoxis transforms into an avatar of Hethiss, the snake god.", JournalEncounterID = 175, OrderIndex = 7, ParentSectionID = 0, FirstChildSectionID = 3486, NextSiblingSectionID = 2792, Type = 1, IconCreatureDisplayInfoID = 37803, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 3, IconFlags = 0, DifficultyMask = -2};
EJ_EncounterSectionDB[2792] = { Title = "Stage Three: Bloodvenom!", Desc = "High Priest Venoxis moves to his altar, absorbs all of the Pools of Acrid Tears in the room, and then casts Bloodvenom. After Bloodvenom ends, Venoxis enters a state of Venom Withdrawal and then returns to stage one.", JournalEncounterID = 175, OrderIndex = 12, ParentSectionID = 0, FirstChildSectionID = 2793, NextSiblingSectionID = 2801, Type = 0, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 3, IconFlags = 0, DifficultyMask = -2};
