EJ_EncounterSectionDB[2794] = { Title = "Venom Withdrawal", Desc = "After Bloodvenom completes, High Priest Venoxis suffers from Venom Withdrawal for $96653d. Venom Withdrawal stuns Venoxis causes him to take $96653s1% additional damage. Once Venom Withdrawal expires, Venoxis begins his stage one activities again.", JournalEncounterID = 175, OrderIndex = 14, ParentSectionID = 2792, FirstChildSectionID = 0, NextSiblingSectionID = 0, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 132108, Flags = 2, IconFlags = 0, DifficultyMask = -2};
