EJ_EncounterSectionDB[2896] = { Title = "Flame Breath", Desc = "Daakara inflicts $43140s3 Fire damage to enemies in a 60 degree cone in front of him. The Flame Breath also leaves a line of fire that inflicts $97497s1 Fire damage every $97497t1 sec. to enemies within $97497A1 yards of the path of flame.", JournalEncounterID = 191, OrderIndex = 23, ParentSectionID = 2895, FirstChildSectionID = 0, NextSiblingSectionID = 2897, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 135805, Flags = 2, IconFlags = 0, DifficultyMask = -2};
