EJ_EncounterSectionDB[2898] = { Title = "Pillar of Fire", Desc = "Daakara summons a pillar of fire at a random player's location. The pillar inflicts $43217s1 Fire damage to enemies within $43217R1 yds. every $43218t1 sec. and persists for $43218d.", JournalEncounterID = 191, OrderIndex = 25, ParentSectionID = 2895, FirstChildSectionID = 0, NextSiblingSectionID = 0, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 135926, Flags = 2, IconFlags = 0, DifficultyMask = -2};
EJ_EncounterSectionDB[2899] = { Title = "Stage One: Welcome to the Great Show!", Desc = "Jin'do fights players alone, dropping Deadzones on the ground to protect himself and calling upon the Spirit of Hakkar to empower his weapon with shadow lightning.", JournalEncounterID = 185, OrderIndex = 1, ParentSectionID = 0, FirstChildSectionID = 2900, NextSiblingSectionID = 2902, Type = 0, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 3, IconFlags = 0, DifficultyMask = -2};
EJ_EncounterSectionDB[2900] = { Title = "Deadzone", Desc = "Jin'do creates a field of deadened magic on the ground at his feet. All units in this field take $97170s1% less magic damage, but have their casting speed reduced by $101360s1%.", JournalEncounterID = 185, OrderIndex = 2, ParentSectionID = 2899, FirstChildSectionID = 0, NextSiblingSectionID = 2901, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 136120, Flags = 2, IconFlags = 0, DifficultyMask = -2};
EJ_EncounterSectionDB[2901] = { Title = "Shadows of Hakkar", Desc = "Jin'do draws power from the Spirit of Hakkar to charge his weapon. For the next $97172d. his attacks unleash bursts of energy that chain to additional targets, inflicting $97173s1 Shadow damage. Each additional target in the chain takes 85% less damage.", JournalEncounterID = 185, OrderIndex = 3, ParentSectionID = 2899, FirstChildSectionID = 0, NextSiblingSectionID = 0, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 135990, Flags = 2, IconFlags = 0, DifficultyMask = -2};
EJ_EncounterSectionDB[2902] = { Title = "Stage Two: Spitting in the Face of a God", Desc = "Jin'do drags his enemies with him into the spirit world. He draws tremendous power from Hakkar's spirit, which is held captive by three large chains.", JournalEncounterID = 185, OrderIndex = 4, ParentSectionID = 0, FirstChildSectionID = 2903, NextSiblingSectionID = 3345, Type = 0, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 3, IconFlags = 0, DifficultyMask = -2};
EJ_EncounterSectionDB[2903] = { Title = "Shadow Spike", Desc = "Jin'do hurls a bolt of shadow at a random player's location. The spike explodes when it hits the ground, inflicting $97161s1 Shadow damage to enemies within $97161a1 yards.", JournalEncounterID = 185, OrderIndex = 5, ParentSectionID = 2902, FirstChildSectionID = 0, NextSiblingSectionID = 2904, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 132843, Flags = 2, IconFlags = 0, DifficultyMask = -2};
EJ_EncounterSectionDB[2904] = { Title = "Gurubashi Spirit", Desc = "Gurubashi Spirits appear in the spirit world wherever players defeat Gurubashi Spirit Warriors in the living world.", JournalEncounterID = 185, OrderIndex = 6, ParentSectionID = 2902, FirstChildSectionID = 2905, NextSiblingSectionID = 2908, Type = 1, IconCreatureDisplayInfoID = 37854, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 2, IconFlags = 0, DifficultyMask = -2};
EJ_EncounterSectionDB[2905] = { Title = "Frenzy", Desc = "Gurubashi Spirits periodically gain $97088s1% attack speed. This effect stacks.", JournalEncounterID = 185, OrderIndex = 7, ParentSectionID = 2904, FirstChildSectionID = 0, NextSiblingSectionID = 2906, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 136149, Flags = 2, IconFlags = 0, DifficultyMask = -2};
EJ_EncounterSectionDB[2906] = { Title = "Body Slam", Desc = "The Gurubashi Spirit jumps to a random target's location, inflicting $97252s1 damage to all units and other objects within $97252A1 yards of that location and knocking them back. This attack leaves a Sundered Rift on the ground, increasing the damage taken by units and objects in the $97320A1 yard radius area by $97320s1% for 20 seconds.", JournalEncounterID = 185, OrderIndex = 8, ParentSectionID = 2904, FirstChildSectionID = 2907, NextSiblingSectionID = 0, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 236171, Flags = 2, IconFlags = 0, DifficultyMask = -2};
EJ_EncounterSectionDB[2907] = { Title = "Sunder Rift", Desc = "The Gurubashi Spirit's Body Slam attack leaves a Sunder Rift on the ground, increasing the damage taken by units and objects in the area by $97320s1% for 20 seconds.", JournalEncounterID = 185, OrderIndex = 9, ParentSectionID = 2906, FirstChildSectionID = 0, NextSiblingSectionID = 0, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 136158, Flags = 2, IconFlags = 0, DifficultyMask = -2};
EJ_EncounterSectionDB[2908] = { Title = "Twisted Spirit", Desc = "Twisted Spirits swarm out of portals around the temple and attack players in increasing numbers. Twisted Spirits inflict Shadow damage when they attack. These creatures have very low health.", JournalEncounterID = 185, OrderIndex = 10, ParentSectionID = 2902, FirstChildSectionID = 0, NextSiblingSectionID = 2909, Type = 1, IconCreatureDisplayInfoID = 25553, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 2, IconFlags = 0, DifficultyMask = -2};
