EJ_EncounterSectionDB[5553] = { Title = "Bone Spike", Desc = "Rattlegore launches a powerful spike of bone at a random player, inflicting $113999s1 Physical damage and knocking them back a great distance. Bone Armor absorbs the effect of Bone Spikes.", JournalEncounterID = 665, OrderIndex = 2, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 5554, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 133724, Flags = 2, IconFlags = 0, DifficultyMask = 3 };
EJ_EncounterSectionDB[5554] = { Title = "Soulflame", Desc = "The souls of the dead Boneweavers continue to torment the living, periodically engulfing a section of the room in Soulflame. The flame inflicts $114009s1 Fire damage every $114007t1 sec. and grows in size over time.", JournalEncounterID = 665, OrderIndex = 3, ParentSectionID = 0, FirstChildSectionID = 0, NextSiblingSectionID = 5560, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 135777, Flags = 2, IconFlags = 0, DifficultyMask = 3 };
EJ_EncounterSectionDB[5558] = { Title = "Stage One: Fetch Me Their Bones!", Desc = "Darkmaster Gandling turns Lilian Voss against her former allies, employing her powerful abilities to gather more corpses for his devious purposes. Though she tries to fight against his dark will, she cannot control her actions at this time.", JournalEncounterID = 666, OrderIndex = 1, ParentSectionID = 0, FirstChildSectionID = 5563, NextSiblingSectionID = 5565, Type = 0, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 3, IconFlags = 0, DifficultyMask = 3 };
EJ_EncounterSectionDB[5560] = { Title = "Bone Pile", Desc = "Bone Piles lie scattered throughout the summoning room. Interacting with a Bone Pile grants a player a charge of Bone Armor.", JournalEncounterID = 665, OrderIndex = 4, ParentSectionID = 0, FirstChildSectionID = 5561, NextSiblingSectionID = 0, Type = 1, IconCreatureDisplayInfoID = 40678, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 2, IconFlags = 0, DifficultyMask = 3 };
