EJ_EncounterSectionDB[5565] = { Title = "Stage Two: Your Soul is Mine!", Desc = "When Lilian's health reaches 60%, her will finally breaks. Darkmaster Gandling forcefully rips her anguished soul from her physical body, then commands Lilian's Soul to attack the players.", JournalEncounterID = 666, OrderIndex = 5, ParentSectionID = 0, FirstChildSectionID = 5567, NextSiblingSectionID = 5569, Type = 0, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 3, IconFlags = 0, DifficultyMask = 3 };
