EJ_EncounterSectionDB[5568] = { Title = "Unleashed Anguish", Desc = "Lilian's anguish is further unleashed when striking players in melee. For every melee strike, Lilian will unleash another barrage of Blazing Soul. However, the movement speed of Lilian's Soul is significantly reduced.", JournalEncounterID = 666, OrderIndex = 7, ParentSectionID = 5565, FirstChildSectionID = 0, NextSiblingSectionID = 5577, Type = 2, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 136221, Flags = 0, IconFlags = 32, DifficultyMask = -1 };
