EJ_EncounterSectionDB[15578] = { Title = "Overview", Desc = "High Warlord Naj'entus periodically skewers players with his Impaling Spines, stunning them until freed by allies. Over the course of the encounter, Naj'entus casts Tidal Shield, becoming immune to damage and restoring health over time until a player hurls a Spine back at him to pierce the bubble.", JournalEncounterID = 1582, OrderIndex = 1, ParentSectionID = 0, FirstChildSectionID = 15579, NextSiblingSectionID = 15587, Type = 3, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 0, IconFlags = 0, DifficultyMask = -1 };
EJ_EncounterSectionDB[15579] = { Title = "Damage Dealers", Desc = "$bullet;Spread out to reduce damage taken from |cFF2959D3|Hspell:39835|h[Needle Spine]|h|r. $bullet;Interact with Naj'entus' Spine to free a player stunned by |cFF2959D3|Hspell:39837|h[Impaling Spine]|h|r. $bullet;Throw Naj'entus' Spine at High Warlord Naj'entus to cancel |cFF2959D3|Hspell:39872|h[Tidal Shield]|h|r.", JournalEncounterID = 1582, OrderIndex = 2, ParentSectionID = 15578, FirstChildSectionID = 0, NextSiblingSectionID = 15580, Type = 3, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 0, IconFlags = 2, DifficultyMask = -1 };
EJ_EncounterSectionDB[15580] = { Title = "Healers", Desc = "$bullet;Spread out to reduce damage taken from |cFF2959D3|Hspell:39835|h[Needle Spine]|h|r. $bullet;Interact with Naj'entus' Spine to free a player stunned by |cFF2959D3|Hspell:39837|h[Impaling Spine]|h|r. $bullet;Throw Naj'entus' Spine at High Warlord Naj'entus to cancel |cFF2959D3|Hspell:39872|h[Tidal Shield]|h|r.", JournalEncounterID = 1582, OrderIndex = 3, ParentSectionID = 15578, FirstChildSectionID = 0, NextSiblingSectionID = 15581, Type = 3, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 0, IconFlags = 4, DifficultyMask = -1 };
EJ_EncounterSectionDB[15581] = { Title = "Tanks", Desc = "$bullet;Avoid facing High Warlord Naj'entus at allies to avoid damage from |cFF2959D3|Hspell:39836|h[Horseshoe Swipe]|h|r. $bullet;Interact with Naj'entus' Spine to free a player stunned by |cFF2959D3|Hspell:39837|h[Impaling Spine]|h|r. $bullet;Throw Naj'entus' Spine at High Warlord Naj'entus to cancel |cFF2959D3|Hspell:39872|h[Tidal Shield]|h|r.", JournalEncounterID = 1582, OrderIndex = 4, ParentSectionID = 15578, FirstChildSectionID = 0, NextSiblingSectionID = 0, Type = 3, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 0, IconFlags = 1, DifficultyMask = -1 };
