EJ_EncounterSectionDB[15588] = { Title = "Overview", Desc = "The gatekeeper Supremus cycles between striking a primary target while creating rivers of fel flame, and fixating on random players while littering the area with volcanic geysers.", JournalEncounterID = 1583, OrderIndex = 1, ParentSectionID = 0, FirstChildSectionID = 15589, NextSiblingSectionID = 15592, Type = 3, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 0, IconFlags = 0, DifficultyMask = -1 };
