EJ_EncounterSectionDB[15599] = { Title = "Overview", Desc = "The objective of the encounter is to assist Akama in defeating the Shade of Akama. Defeat Ashtongue Channelers and Sorcerers to allow the Shade of Akama to reach Akama, starting Stage Two. Once Stage Two begins, defeat the Shade of Akama to win the encounter before Akama is slain.", JournalEncounterID = 1584, OrderIndex = 1, ParentSectionID = 0, FirstChildSectionID = 15600, NextSiblingSectionID = 15603, Type = 3, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 0, IconFlags = 0, DifficultyMask = -1 };
