EJ_EncounterSectionDB[15628] = { Title = "Overview", Desc = "Teron Gorefiend periodically marks a player with |cFF2959D3|Hspell:40251|h[Shadow of Death]|h|r, killing them instantly. The slain player then returns as a Vengeful Spirit, with the unique ability to hinder and destroy Shadowy Constructs that will otherwise decimate other players.", JournalEncounterID = 1585, OrderIndex = 1, ParentSectionID = 0, FirstChildSectionID = 15629, NextSiblingSectionID = 15632, Type = 3, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 0, IconFlags = 0, DifficultyMask = -1 };
EJ_EncounterSectionDB[15629] = { Title = "Damage Dealers", Desc = "$bullet;Be prepared to become a |cFF2959D3|Hspell:40251|h[Shadow of Death].|h|r", JournalEncounterID = 1585, OrderIndex = 2, ParentSectionID = 15628, FirstChildSectionID = 0, NextSiblingSectionID = 15630, Type = 3, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 0, IconFlags = 2, DifficultyMask = -1 };
EJ_EncounterSectionDB[15630] = { Title = "Healers", Desc = "$bullet;Be prepared to become a |cFF2959D3|Hspell:40251|h[Shadow of Death].|h|r $bullet;Be quick to dispel |cFF2959D3|Hspell:40239|h[Incinerate]|h|r to avoid damage. $bullet;Targets afflicted by |cFF2959D3|Hspell:40243|h[Crushing Shadows]|h|r are especially susceptible to Shadow damage.", JournalEncounterID = 1585, OrderIndex = 3, ParentSectionID = 15628, FirstChildSectionID = 0, NextSiblingSectionID = 15631, Type = 3, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 0, IconFlags = 4, DifficultyMask = -1 };
