EJ_EncounterSectionDB[15645] = { Title = "Overview", Desc = "As the fight progresses, the Gurtogg swaps between two modes that determine which abilities he uses. In one mode, he afflicts distant targets with deadly maladies, while in the other he fixates on a random player with his full might.", JournalEncounterID = 1586, OrderIndex = 1, ParentSectionID = 0, FirstChildSectionID = 15646, NextSiblingSectionID = 15649, Type = 3, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 0, IconFlags = 0, DifficultyMask = -1 };
EJ_EncounterSectionDB[15646] = { Title = "Damage Dealers", Desc = "$bullet;Coordinate your positioning with group members to avoid getting too many stacks of |cFF2959D3|Hspell:42005|h[Blood Boil]|h|r.", JournalEncounterID = 1586, OrderIndex = 2, ParentSectionID = 15645, FirstChildSectionID = 0, NextSiblingSectionID = 15647, Type = 3, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 0, IconFlags = 2, DifficultyMask = -1 };
EJ_EncounterSectionDB[15647] = { Title = "Healers", Desc = "$bullet;Coordinate your positioning with group members to avoid getting too many stacks of |cFF2959D3|Hspell:42005|h[Blood Boil]|h|r.$bullet;Heal the ally that is targeted with |cFF2959D3|Hspell:40604|h[Fel Rage]|h|r.", JournalEncounterID = 1586, OrderIndex = 3, ParentSectionID = 15645, FirstChildSectionID = 0, NextSiblingSectionID = 15648, Type = 3, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 0, IconFlags = 4, DifficultyMask = -1 };
