EJ_EncounterSectionDB[15661] = { Title = "Overview", Desc = "The Reliquary of Souls manifests three different Essences over the course of the encounter, each of which applies unique effects that must be handled differently.  First, the Essence of Suffering always strikes the nearest player and afflicts the raid with |cFF2959D3|Hspell:41292|h[Aura of Suffering]|h|r. Second, the Essence of Desire afflicts the raid with |cFF2959D3|Hspell:41350|h[Aura of Desire]|h|r. Finally, players must defeat the Essence of Anger which afflicts the raid with |cFF2959D3|Hspell:41337|h[Aura of Anger]|h|r.", JournalEncounterID = 1587, OrderIndex = 1, ParentSectionID = 0, FirstChildSectionID = 15662, NextSiblingSectionID = 15665, Type = 3, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 0, IconFlags = 0, DifficultyMask = -1 };
EJ_EncounterSectionDB[15662] = { Title = "Damage Dealers", Desc = "$bullet;Avoid heavily damaging yourself during |cFF2959D3|Hspell:41350|h[Aura of Desire]|h|r. $bullet;Be aware of your threat while|cFF2959D3|Hspell:41520|h[Seethe]|h|r is active.", JournalEncounterID = 1587, OrderIndex = 2, ParentSectionID = 15661, FirstChildSectionID = 0, NextSiblingSectionID = 15663, Type = 3, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 0, IconFlags = 2, DifficultyMask = -1 };
EJ_EncounterSectionDB[15663] = { Title = "Healers", Desc = "$bullet;Watch your mana during |cFF2959D3|Hspell:41292|h[Aura of Suffering]|h|r. $bullet;Quickly dispel |cFF2959D3|Hspell:41303|h[Soul Drain]|h|r. $bullet;Regenerate Mana from the Enslaved Souls during the Intermission stage.", JournalEncounterID = 1587, OrderIndex = 3, ParentSectionID = 15661, FirstChildSectionID = 0, NextSiblingSectionID = 15664, Type = 3, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 0, IconFlags = 4, DifficultyMask = -1 };
EJ_EncounterSectionDB[15664] = { Title = "Tanks", Desc = "$bullet;While the Essence of Desire is active, be careful of |cFF2959D3|Hspell:41410|h[Deaden]|h|r. $bullet;Using a Taunt effect while the Essence of Anger is active will cause |cFF2959D3|Hspell:41364|h[Seethe]|h|r. $bullet;Face the Essence of Anger away from allies to avoid damage from |cFF2959D3|Hspell:41545|h[Soul Scream]|h|r.", JournalEncounterID = 1587, OrderIndex = 4, ParentSectionID = 15661, FirstChildSectionID = 0, NextSiblingSectionID = 0, Type = 3, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 0, IconFlags = 1, DifficultyMask = -1 };
