EJ_EncounterSectionDB[15687] = { Title = "Overview", Desc = "Mother Shahraz will link allies together with |cFF2959D3|Hspell:41001|h[Fatal Attraction]|h|r while also dealing heavy damage to the raid with her Beams.", JournalEncounterID = 1588, OrderIndex = 1, ParentSectionID = 0, FirstChildSectionID = 15688, NextSiblingSectionID = 15691, Type = 3, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 0, IconFlags = 0, DifficultyMask = -1 };
