EJ_EncounterSectionDB[15700] = { Title = "Overview", Desc = "The Illidari Council consists of a powerful paladin, rogue, mage, and priest. They share health and bring their iconic abilities to bear against their foes.", JournalEncounterID = 1589, OrderIndex = 1, ParentSectionID = 0, FirstChildSectionID = 15701, NextSiblingSectionID = 15704, Type = 3, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 0, IconFlags = 0, DifficultyMask = -1 };
EJ_EncounterSectionDB[15701] = { Title = "Damage Dealers", Desc = "$bullet;Melee damage dealers should avoid striking High Nethermancer Zerevor due to his |cFF2959D3|Hspell:41524|h[Arcane Explosion]|h|r. $bullet;Interrupt Lady Malande's |cFF2959D3|Hspell:41455|h[Circle of Healing]|h|r.", JournalEncounterID = 1589, OrderIndex = 2, ParentSectionID = 15700, FirstChildSectionID = 0, NextSiblingSectionID = 15702, Type = 3, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 0, IconFlags = 2, DifficultyMask = -1 };
