EJ_EncounterSectionDB[15731] = { Title = "Overview", Desc = "Illidan wields his Warglaives at the start of the encounter, infecting foes with |cFF2959D3|Hspell:41917|h[Parasitic Shadowfiend]|h|r. Upon reaching 65% health, Illidan takes flight and throws the Warglaives of Azzinoth to the ground, each of which unleashes a Flame. The two Flames of Azzinoth must be defeated to bring Illidan to the ground. For the remainder of the encounter, Illidan periodically unleashes the power of the demonic force within him, using those dark powers to assault his foes, before returning to his natural form. At 30% health, Maiev arrives to assist in handling the Betrayer's final efforts to overpower his foes.", JournalEncounterID = 1590, OrderIndex = 1, ParentSectionID = 0, FirstChildSectionID = 15732, NextSiblingSectionID = 15735, Type = 3, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 0, IconFlags = 0, DifficultyMask = -1 };
EJ_EncounterSectionDB[15732] = { Title = "Damage Dealers", Desc = "$bullet;Move away from allies when afflicted with |cFF2959D3|Hspell:41917|h[Parasitic Shadowfiend]|h|r. $bullet;Quickly defeat the Flames of Azzinoth in Stage Two of the encounter.", JournalEncounterID = 1590, OrderIndex = 2, ParentSectionID = 15731, FirstChildSectionID = 0, NextSiblingSectionID = 15733, Type = 3, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 0, IconFlags = 2, DifficultyMask = -1 };
