EJ_EncounterSectionDB[15734] = { Title = "Tanks", Desc = "$bullet;Use Active Mitigation defensive abilities to survive |cFF2959D3|Hspell:41032|h[Shear]|h|r. $bullet;Move Illidan Stormrage to avoid damage taken from |cFF2959D3|Hspell:40832|h[Flame Crash]|h|r. $bullet;In Stage Two, be quick to grab the attention of the Flames of Azzinoth.", JournalEncounterID = 1590, OrderIndex = 4, ParentSectionID = 15731, FirstChildSectionID = 0, NextSiblingSectionID = 0, Type = 3, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 0, IconFlags = 1, DifficultyMask = -1 };
