EJ_EncounterSectionDB[17182] = { Title = "Overview", Desc = "The Flame Leviathan will target and pursue after random Siege Vehicles and quickly destroy any vehicle that it catches! Use the Vehicles supplied by the Explorer's League to avoid and ensare the Flame Leviathan.", JournalEncounterID = 1637, OrderIndex = 1, ParentSectionID = 0, FirstChildSectionID = 17184, NextSiblingSectionID = 17186, Type = 3, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 0, IconFlags = 0, DifficultyMask = -1 };
EJ_EncounterSectionDB[17183] = { Title = "Demolisher", Desc = "$bullet;All Siege Vehicles should flee when Pursued by the Flame Leviathan. $bullet;Demolisher Drivers can light allied |cFF2959D3|Hspell:62286|h[Tar]|h|r on fire. $bullet;Demolisher Passengers can also |cFF2959D3|Hspell:64414|h[Load Into Catapult]|h|r, allowing their driver to hurl them on top of the Flame Leviathan.", JournalEncounterID = 1637, OrderIndex = 3, ParentSectionID = 17182, FirstChildSectionID = 0, NextSiblingSectionID = 17185, Type = 3, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 0, IconFlags = 0, DifficultyMask = -1 };
EJ_EncounterSectionDB[17184] = { Title = "Siege Engine", Desc = "$bullet;All Siege Vehicles should flee when Pursued by the Flame Leviathan. $bullet;Siege Engine Drivers should interrupt |cFF2959D3|Hspell:62396|h[Flame Vents]|h|r using |cFF2959D3|Hspell:62522|h[Electroshock]|h|r. $bullet;Siege Engine Passengers should shoot down Pyrite Ammo from overhead to resupply allies.", JournalEncounterID = 1637, OrderIndex = 2, ParentSectionID = 17182, FirstChildSectionID = 0, NextSiblingSectionID = 17183, Type = 3, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 0, IconFlags = 0, DifficultyMask = -1 };
EJ_EncounterSectionDB[17185] = { Title = "Chopper", Desc = "$bullet;All Siege Vehicles should flee when Pursued by the Flame Leviathan. $bullet;Use the Chopper to place |cFF2959D3|Hspell:62286|h[Tar]|h|r onto the battlefield.", JournalEncounterID = 1637, OrderIndex = 4, ParentSectionID = 17182, FirstChildSectionID = 0, NextSiblingSectionID = 0, Type = 3, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 0, IconFlags = 0, DifficultyMask = -1 };
