EJ_EncounterSectionDB[17346] = { Title = "Overview", Desc = "Auriaya patrols the Observation Ring with her four Sanctum Sentries which will ravage their target with a |cFF2959D3|Hspell:64666|h[Savage Pounce]|h|r when engaged. She summons other guardians during the encounter which she commands to disrupt her enemies.", JournalEncounterID = 1643, OrderIndex = 1, ParentSectionID = 0, FirstChildSectionID = 17347, NextSiblingSectionID = 17350, Type = 3, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 0, IconFlags = 0, DifficultyMask = -1 };
EJ_EncounterSectionDB[17347] = { Title = "Damage Dealers", Desc = "$bullet;Stop casting spells to avoid being interrupted while the Feral Defender is casting |cFF2959D3|Hspell:64496|h[Feral Rush]|h|r. $bullet;Interrupt Auriaya's casts of |cFF2959D3|Hspell:64389|h[Sentinel Blast]|h|r. $bullet;Assist in splitting the damage of |cFF2959D3|Hspell:64422|h[Sonic Screech]|h|r.", JournalEncounterID = 1643, OrderIndex = 2, ParentSectionID = 17346, FirstChildSectionID = 0, NextSiblingSectionID = 17348, Type = 3, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 0, IconFlags = 2, DifficultyMask = -1 };
