EJ_EncounterSectionDB[17579] = { Title = "Overview", Desc = "Mimiron engages his enemies with inventions rather than directly in combat. The Leviathan MK II is a deadly vehicle that assaults the Tank with powerful attacks, the VX-001 which strikes enemies with rocket blasts and laser barrages, the Aerial Command Unit which engages enemies from the skies, and finally the V0-L7R-0N unit, which combines the might of all of his inventions.", JournalEncounterID = 1647, OrderIndex = 1, ParentSectionID = 0, FirstChildSectionID = 17580, NextSiblingSectionID = 17583, Type = 3, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 0, IconFlags = 0, DifficultyMask = -1 };
EJ_EncounterSectionDB[17580] = { Title = "Damage Dealers", Desc = "$bullet;Avoid the Leviathan Mk II's |cFF2959D3|Hspell:63016|h[Proximity Mines]|h|r when fleeing from |cFF2959D3|Hspell:63631|h[Shock Blast]|h|r.$bullet;Be spread apart to avoid the Leviathan Mk II's |cFF2959D3|Hspell:63666|h[Napalm Shell]|h|r.$bullet;Rotate away from VX-001's |cFF2959D3|Hspell:63293|h[P3Wx2 Laser Barrage]|h|r ability.$bullet;Use the Magnetic Core dropped by the Assault Bot to ground the Aerial Command Unit.", JournalEncounterID = 1647, OrderIndex = 2, ParentSectionID = 17579, FirstChildSectionID = 0, NextSiblingSectionID = 17581, Type = 3, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 0, IconFlags = 2, DifficultyMask = -1 };
EJ_EncounterSectionDB[17581] = { Title = "Healers", Desc = "$bullet;Be spread apart to avoid the Leviathan Mk II's |cFF2959D3|Hspell:63666|h[Napalm Shell]|h|r.$bullet;Prepare for heavy damage on the Tank when the Leviathan Mk II casts |cFF2959D3|Hspell:62997|h[Plasma Blast]|h|r.$bullet;Rotate away from VX-001's |cFF2959D3|Hspell:63293|h[P3Wx2 Laser Barrage]|h|r ability.", JournalEncounterID = 1647, OrderIndex = 3, ParentSectionID = 17579, FirstChildSectionID = 0, NextSiblingSectionID = 17582, Type = 3, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 0, IconFlags = 4, DifficultyMask = -1 };
