EJ_EncounterSectionDB[17653] = { Title = "Overview", Desc = "Sara must be damaged by Guardians of Yogg-Saron's |cFF2959D3|Hspell:62714|h[Shadow Nova]|h|r, once damaged significantly, Yogg Saron will reveal himself and begin to attack the sanity of his enemies, which is depleted will turn his enemies against one another.  Periodically portals will appear which grant players access to the Brain of Yogg-Saron, while inside they must dispel illusions in order to escape, before they are afflicted with |cFF2959D3|Hspell:64059|h[Induce Madness]|h|r.  When the Brain of Yogg-Saron reaches 30% health remaining, Yogg Saron's |cFF2959D3|Hspell:63894|h[Shadowy Barrier]|h|r will fall and he can be assaulted directly.", JournalEncounterID = 1649, OrderIndex = 1, ParentSectionID = 0, FirstChildSectionID = 17654, NextSiblingSectionID = 17670, Type = 3, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 0, IconFlags = 0, DifficultyMask = -1 };
EJ_EncounterSectionDB[17654] = { Title = "Damage Dealers", Desc = "$bullet;During Stage One defeat the Guardians of Yogg-Saron nearby Sara in order to damage her.$bullet;Enter the Descent into Madness and defeat the illusions to gain access to the Brain of Yogg-Saron.$bullet;Avoid losing all of your |cFF2959D3|Hspell:63050|h[Sanity]|h|r.$bullet;Stand close to your allies when connected by |cFF2959D3|Hspell:63802|h[Brain Link]|h|r.", JournalEncounterID = 1649, OrderIndex = 2, ParentSectionID = 17653, FirstChildSectionID = 0, NextSiblingSectionID = 17655, Type = 3, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 0, IconFlags = 2, DifficultyMask = -1 };
EJ_EncounterSectionDB[17655] = { Title = "Healers", Desc = "$bullet;Avoid losing all of your |cFF2959D3|Hspell:63050|h[Sanity]|h|r.$bullet;Enter the Descent into Madness and defeat the illusions to gain access to the Brain of Yogg-Saron.$bullet;Stand close to your allies when connected by |cFF2959D3|Hspell:63802|h[Brain Link]|h|r.", JournalEncounterID = 1649, OrderIndex = 3, ParentSectionID = 17653, FirstChildSectionID = 0, NextSiblingSectionID = 17656, Type = 3, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 0, IconFlags = 4, DifficultyMask = -1 };
EJ_EncounterSectionDB[17656] = { Title = "Tank", Desc = "$bullet;Position Guardians of Yogg-Saron near Sara to damage her with |cFF2959D3|Hspell:62714|h[Shadow Nova]|h|r.$bullet;Avoid losing all of your |cFF2959D3|Hspell:63050|h[Sanity]|h|r.$bullet;Be quick to grab the attention of Crusher Tentacles and Immortal Guardians as they spawn.$bullet;Prevent Immortal Guardians from healing by moving ones with |cFF2959D3|Hspell:64468|h[ Empowering Shadows]|h|r away.", JournalEncounterID = 1649, OrderIndex = 4, ParentSectionID = 17653, FirstChildSectionID = 0, NextSiblingSectionID = 0, Type = 3, IconCreatureDisplayInfoID = 0, UiModelSceneID = 0, SpellID = 0, IconFileDataID = 0, Flags = 0, IconFlags = 1, DifficultyMask = -1 };
